INSERT INTO `posts` VALUES (1,1,'{\"vi\":\"test bài viết số 1\"}','test-bai-viet-so-1','{\"vi\":\"test bài viết số 1\"}','{\"vi\":\"test bài viết số 1\"}','{\"vi\":\"<p>Là người chi tiêu tằn tiện, nhưng mỗi khi nhắc đến đồ chơi mô hình, Zhu Zuoyi không ngần ngại mở hầu bao.</p><p>Phòng ngủ của Zhu Zuoyi, 24 tuổi ở Vũ Hán, trưng bày đầy ắp đồ chơi mô hình, phụ kiện, trong đó có nhiều búp bê LuLu the Piggy và bộ sưu tập nhân vật từ Sanrio, công ty Nhật Bản sở hữu thương hiệu Hello Kitty.</p><p>Zhu thường kiểm soát chặt chẽ chi tiêu hàng ngày, chi chưa đầy 20 tệ (2,74 USD) cho các bữa ăn, nhưng sẵn sàng bỏ ra hàng chục USD mỗi tháng để mua những món đồ chơi này.</p><p>\\\"Đây là khoản đầu tư về mặt cảm xúc. Có những con búp bê dễ thương bên mình khiến tôi cảm thấy hạnh phúc, đủ đầy\\\", Zhu nói, lưu ý khoản chi cho đồ chơi bằng khoảng 1/3 số tiền cô dùng mua thực phẩm.</p><p>Zhu thuộc lớp người tiêu dùng trẻ thúc đẩy nền kinh tế đồ chơi ở Trung Quốc, tập trung vào các vật phẩm như búp bê, huy hiệu, áp phích, thẻ bài, dựa theo các nhân vật, cốt truyện từ vũ trụ anime, truyện tranh, game, tiểu thuyết (ACGN).</p><p>Tập đoàn nghiên cứu thị trường Trung Quốc iiMedia Research tháng 12/2024 cho hay thị trường ACGN ở nước này đang bùng nổ. Giá trị của nền kinh tế đồ chơi gắn liền với thị trường này đạt 23 tỷ USD trong năm 2024, tăng 40% so với 2023, và dự kiến tăng lên 41 tỷ USD vào năm 2029.</p><p>&nbsp;</p><p><picture><source srcset=\\\"https://i1-vnexpress.vnecdn.net/2025/01/14/fa9d403e-e7f9-484d-8607-f1f32f-7968-7113-1736844672.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=MXfKtotgCRNuJ3OohDbLDQ 1x, https://i1-vnexpress.vnecdn.net/2025/01/14/fa9d403e-e7f9-484d-8607-f1f32f-7968-7113-1736844672.jpg?w=1020&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=YAqSlsO2zhajWrsDC8R_Ew 1.5x, https://i1-vnexpress.vnecdn.net/2025/01/14/fa9d403e-e7f9-484d-8607-f1f32f-7968-7113-1736844672.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=2&amp;fit=crop&amp;s=XCtvjXpqTNyQZr7ZGCpuNg 2x\\\"><img src=\\\"https://i1-vnexpress.vnecdn.net/2025/01/14/fa9d403e-e7f9-484d-8607-f1f32f-7968-7113-1736844672.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=MXfKtotgCRNuJ3OohDbLDQ\\\" alt=\\\"Một gian trưng bày đồ chơi mô hình của Pop Mart ở Bắc Kinh. Ảnh: AP\\\"></picture></p><p><br>&nbsp;</p>\"}','dv-img-4-bmqcnkhi-pkPA.jpg','{\"vi\":\"test bài viết số 1\"}',NULL,1,'2025-01-14 10:55:47','2025-01-14 10:58:28');
